bomData.valueScript:
// Filter function to get all the hardware elements
let HardwareElements = GlobalFunc.find_HardwareLibraryMapping(part.pa_HardwareId);

// Cycle to add all hardware elements to the BOM
HardwareElements.forEach(info => {

	  let BOMInfo = GlobalFunc.find_HardwareLibrary(info.SupplierArticleNumber!,info.Supplier!);
	  let BOMName = GlobalFunc.find_PartSettings("part_HangerSystem");
	  let tmpLength = BOMInfo.Length;
	  let tmpQty = info.BomQty;
	  if(BOMInfo.Category != 'WallPlate' || BOMInfo.Category == 'WallPlate' && part.pa_WallPlateLengthLeft == 0 && part.pa_WallPlateLengthRight == 0 )
	  {
		  let elem = this.addbomout_Hardware();
		  elem.bom_Supplier=info.Supplier;
		  elem.bom_SupplierArticle=info.SupplierArticleNumber;
		  elem.bom_Description1=BOMInfo.Description;
		  elem.bom_Description2=BOMInfo.Description2;
		  elem.bom_Length=BOMInfo.Length;
		  elem.bom_Width=BOMInfo.Width;
		  elem.bom_Thk=BOMInfo.Thickness;
		  elem.bom_Color=BOMInfo.Color;
		  elem.bom_Weight=BOMInfo.Weight;
		  elem.bom_Name=BOMName.BomPartDescription;
		  elem.bom_Type=part._partId;
		  elem.bom_PartId=part._id;
		  elem.bom_ParentId=parentId;
		  elem.bom_Qty=info.BomQty;		
	  }
	  else
	  {
		if(part.pa_WallPlateLengthLeft > 0)
		  {
			  let elem = this.addbomout_Hardware();
			  elem.bom_Supplier=info.Supplier;
			  elem.bom_SupplierArticle=info.SupplierArticleNumber;
			  elem.bom_Description1=BOMInfo.Description;
			  elem.bom_Description2=BOMInfo.Description2;
			  elem.bom_Length=part.pa_WallPlateLengthLeft;
			  elem.bom_Width=BOMInfo.Width;
			  elem.bom_Thk=BOMInfo.Thickness;
			  elem.bom_Color=BOMInfo.Color;
			  elem.bom_Weight=BOMInfo.Weight;
			  elem.bom_Name=BOMName.BomPartDescription;
			  elem.bom_Type=part._partId;
			  elem.bom_PartId=part._id;
			  elem.bom_ParentId=parentId;
			  elem.bom_Qty=1;		
		  }
		if(part.pa_WallPlateLengthRight > 0)
		  {
			  let elem = this.addbomout_Hardware();
			  elem.bom_Supplier=info.Supplier;
			  elem.bom_SupplierArticle=info.SupplierArticleNumber;
			  elem.bom_Description1=BOMInfo.Description;
			  elem.bom_Description2=BOMInfo.Description2;
			  elem.bom_Length=part.pa_WallPlateLengthRight;
			  elem.bom_Width=BOMInfo.Width;
			  elem.bom_Thk=BOMInfo.Thickness;
			  elem.bom_Color=BOMInfo.Color;
			  elem.bom_Weight=BOMInfo.Weight;
			  elem.bom_Name=BOMName.BomPartDescription;
			  elem.bom_Type=part._partId;
			  elem.bom_PartId=part._id;
			  elem.bom_ParentId=parentId;
			  elem.bom_Qty=1;		
		  }



	  }



})
